// 读取规则文档内容
var ruleDocPath = "/Users/cassia/Desktop/dyx/wpsjs/3. 中水设计文档校排/规则.docx";
var app = WPS.Application;
var docs = app.Documents;

// 查找已打开的规则文档
var ruleDoc = null;
for (var i = 0; i < docs.Count; i++) {
    var doc = docs.Item(i + 1);
    if (doc.FullName.indexOf("规则.docx") !== -1) {
        ruleDoc = doc;
        break;
    }
}

if (!ruleDoc) {
    return { error: "未找到规则文档，请先打开" };
}

// 读取所有段落内容
var content = "";
var paras = ruleDoc.Paragraphs;
for (var j = 0; j < paras.Count; j++) {
    content += paras.Item(j + 1).Range.Text;
}

return { success: true, content: content };

